// Re-encode all WebP files in public/images to strip ALL metadata and bake in
// any remaining EXIF orientation. This ensures AVIF generated by Next/sharp
// from these cleaned WebPs will be perfectly synced pixel-wise.
//
// Usage: node scripts/clean-webp-metadata.mjs

import { readdir, rename, readFile, writeFile } from "node:fs/promises";
import { resolve, join, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import sharp from "sharp";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");
const IMAGES_DIR = resolve(ROOT, "public/images");

async function walk(dir) {
  const out = [];
  for (const e of await readdir(dir, { withFileTypes: true })) {
    const full = join(dir, e.name);
    if (e.isDirectory()) out.push(...(await walk(full)));
    else if (e.isFile() && e.name.toLowerCase().endsWith(".webp")) out.push(full);
  }
  return out;
}

function humanKB(b) {
  return (b / 1024).toFixed(1) + " KB";
}

const files = await walk(IMAGES_DIR);
console.log(`Cleaning ${files.length} WebP files…\n`);

let orientationFixed = 0;
let metadataStripped = 0;
let unchanged = 0;
let errors = 0;

for (const f of files) {
  try {
    const beforeBuf = await readFile(f);
    const beforeMeta = await sharp(beforeBuf).metadata();
    const hadOrientation = !!beforeMeta.orientation && beforeMeta.orientation !== 1;
    const hadMetadata = !!(beforeMeta.exif || beforeMeta.icc || beforeMeta.iptc || beforeMeta.xmp);

    // Build clean pipeline:
    // - .rotate() no-args = applies EXIF orientation then strips it
    // - Re-encode as fresh WebP, quality 85 (matches default)
    // - By default sharp strips all metadata on output unless .withMetadata() is called
    const cleanBuf = await sharp(beforeBuf)
      .rotate() // apply EXIF orientation + strip
      .webp({ quality: 85, effort: 6, smartSubsample: true })
      .toBuffer();

    // Verify cleaned
    const afterMeta = await sharp(cleanBuf).metadata();
    if (afterMeta.orientation && afterMeta.orientation !== 1) {
      console.warn(`  ⚠ ${f.replace(ROOT + "/", "")}: orientation persisted (${afterMeta.orientation})`);
    }

    // Write atomically
    const tmp = f + ".tmp";
    await writeFile(tmp, cleanBuf);
    await rename(tmp, f);

    const beforeSize = beforeBuf.length;
    const afterSize = cleanBuf.length;
    const changed = hadOrientation || hadMetadata || Math.abs(beforeSize - afterSize) > beforeSize * 0.02;

    if (hadOrientation) {
      orientationFixed++;
      console.log(`  🔄 ${f.replace(ROOT + "/", "")} (orient=${beforeMeta.orientation} baked in, ${humanKB(beforeSize)} → ${humanKB(afterSize)})`);
    } else if (hadMetadata) {
      metadataStripped++;
      console.log(`  🧹 ${f.replace(ROOT + "/", "")} (metadata stripped, ${humanKB(beforeSize)} → ${humanKB(afterSize)})`);
    } else if (changed) {
      console.log(`  ~  ${f.replace(ROOT + "/", "")} (re-encoded, ${humanKB(beforeSize)} → ${humanKB(afterSize)})`);
    } else {
      unchanged++;
    }
  } catch (err) {
    errors++;
    console.warn(`  ❌ ${f.replace(ROOT + "/", "")}: ${err.message}`);
  }
}

console.log(`\nDone:`);
console.log(`  ${orientationFixed} files with EXIF orientation baked in`);
console.log(`  ${metadataStripped} files with extraneous metadata stripped`);
console.log(`  ${unchanged} files already clean (re-encoded anyway)`);
console.log(`  ${errors} errors`);
